"""Filename: kg_merge_parameters.pyDescription: Performs Knowledge Fusion by ingesting the raw NEV parameter dataset              and establishing hierarchical topological connections (Manufacturer ->              Car Class -> Vehicle Series -> Specific Variant) onto the base ontology."""import pandas as pdimport reimport osfrom neo4j import GraphDatabase# ==========================================# Database Configuration# ==========================================URI = "bolt://localhost:7687"USER = "neo4j"# NOTE: Replace 'YOUR_PASSWORD_HERE' with your actual Neo4j password when running locally.PASSWORD = os.getenv("NEO4J_PASSWORD", "YOUR_PASSWORD_HERE")def extract_base_series(long_name):    """    Core Algorithm: Extracts the base vehicle series name from detailed variant strings.    Example: 'Tank 300 2022 Border Limited' -> 'Tank 300'    """    match = re.search(r'^(.*?)\s*\d{4}款', str(long_name))    if match:        return match.group(1).strip()    return str(long_name).split(' ')[0]def merge_vehicle_parameters():    print("[INFO] Connecting to Neo4j database...")    driver = GraphDatabase.driver(URI, auth=(USER, PASSWORD))    print("[INFO] Loading raw vehicle parameter dataset for knowledge fusion...")    try:        # Note: 'test.csv' is renamed to 'Vehicle_Parameters.csv' for professional standards        df = pd.read_csv('../Data/Vehicle_Parameters.csv', encoding='utf-8-sig').fillna('Unknown')    except FileNotFoundError:        print("[ERROR] Vehicle_Parameters.csv not found in the Data directory.")        return    # Standardize textual data    for col in ['车型', '厂商', '级别', '能源类型']:        if col in df.columns:            df[col] = df[col].astype(str).str.strip()    df['base_name'] = df['车型'].apply(extract_base_series)    print(f"[INFO] Processing {len(df)} vehicle variants for hierarchical integration.")    with driver.session() as session:        print("[INFO] Executing topological merge operations. Please wait...")        merge_query = """        UNWIND $batch AS row        // 1. Match or create base vehicle series (Bridge to the existing Ontology)        MERGE (series:Entity {name: row.base_name})        SET series:CarModel        // 2. Instantiate specific vehicle variants with full attributes        MERGE (variant:Entity {name: row.车型})        SET variant:CarVariant        SET variant += row          // 3. Establish hierarchical links (Variant -> Series)        MERGE (variant)-[:VARIANT_OF]->(series)        // 4. Mount manufacturer, class, and energy type entities        MERGE (mfg:Entity {name: row.厂商})        SET mfg:Manufacturer        MERGE (cls:Entity {name: row.级别})        SET cls:CarClass        MERGE (nrg:Entity {name: row.能源类型})        SET nrg:EnergyType        MERGE (mfg)-[:PRODUCES]->(variant)        MERGE (variant)-[:BELONGS_TO_CLASS]->(cls)        MERGE (variant)-[:USES_ENERGY]->(nrg)        """        records = df.to_dict('records')        session.run(merge_query, batch=records)        nodes_count = session.run("MATCH (n) RETURN count(n)").single()[0]        print("\n[SUCCESS] Heterogeneous Parameter Integration Completed.")        print(f"[STAT] Graph node count surged to: {nodes_count} post-fusion.")    driver.close()if __name__ == "__main__":    merge_vehicle_parameters()